fn read_string() -> String {
    let mut input = String::new();
    std::io::stdin().read_line(&mut input).expect("Failed");
    input
}

fn main(){

    let mut x = read_string();
    x = x.replace("\r", "");
    let vec: Vec<&str> = x.split("").collect();
    let mut found: bool =  false;
    for n in 2..(vec.len()-3){
        if ((vec[n] != ".") && (vec[n+1] != ".") && (vec[n-1] != ".")) &&
            ((vec[n] != vec[n+1]) && (vec[n-1] != vec[n+1]) && (vec[n] != vec[n-1]))
            {
            found = true;
            break
        }
    }
    println!("{}", if found {"YES"} else {"NO"});
}
